#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int sum = 0;
        for (int i = 0; i < N; i++) {
            sum += A[i];
        }
        if (sum >= K) {
            printf("1\n");
        } else {
            printf("2\n");
        }
    }
    return 0;
}

