code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int sum = 0;
            for (int i = 0; i < N; i++) {
                sum += A[i];
            }
            if (sum >= K) {
                System.out.println("1");
            } else {
                System.out.println("2");
            }
        }
    }
}

